def normalize(azure, aws, gcp):
    rows = []
    for r in azure:
        rows.append((r["resourceGroup"], r["costUSD"]))
    for r in aws:
        rows.append((r["tag_team"], r["unblended_cost"]))
    for r in gcp:
        rows.append((r["label_team"], r["cost"]))
    return rows
